# ── Alpaca API helpers ────────────────────────────────────────────────────────
def _h():
    return {
        "APCA-API-KEY-ID":     ALPACA_KEY,
        "APCA-API-SECRET-KEY": ALPACA_SECRET,
        "Content-Type":        "application/json",
    }

def alpaca_get(path):
    r = requests.get(f"{ALPACA_BASE}{path}", headers=_h(), timeout=15)
    r.raise_for_status()
    return r.json()

def alpaca_post(path, data):
    r = requests.post(f"{ALPACA_BASE}{path}", headers=_h(), json=data, timeout=15)
    r.raise_for_status()
    return r.json()


def close_equity_position(sym: str) -> tuple:
    """Close an equity position using DELETE /v2/positions/{sym}.
    Returns (success: bool, status_code: int, error_text: str).
    More reliable than sell orders — avoids fractional qty precision rejections.
    """
    try:
        r = requests.delete(f"{ALPACA_BASE}/v2/positions/{sym}", headers=_h(), timeout=10)
        if r.status_code in (200, 201, 204):
            return True, r.status_code, ""
        if r.status_code == 404:
            return True, 404, "already_closed"
        return False, r.status_code, r.text[:150]
    except Exception as e:
        return False, 0, str(e)[:150]


def alpaca_snapshots(symbols: list) -> dict:
    """Fetch real-time Alpaca snapshots for a list of symbols.
    Returns dict of {symbol: {chg_pct, volume, prev_close, price, vol_ratio_est}}.
    Uses Alpaca Data API — much faster than yfinance for pre-screening.
    """
    if not symbols:
        return {}
    result = {}
    CHUNK = 500
    for i in range(0, len(symbols), CHUNK):
        chunk = symbols[i : i + CHUNK]
        try:
            sym_str = ",".join(chunk)
            r = requests.get(
                f"{ALPACA_DATA_BASE}/v2/stocks/snapshots",
                headers=_h(),
                params={"symbols": sym_str, "feed": "iex"},
                timeout=15,
            )
            if r.status_code != 200:
                continue
            data = r.json()
            for sym, snap in data.items():
                try:
                    daily = snap.get("dailyBar", {}) or {}
                    prev  = snap.get("prevDailyBar", {}) or {}
                    trade = snap.get("latestTrade", {}) or {}
                    price = float(trade.get("p", 0) or daily.get("c", 0) or 0)
                    prev_c = float(prev.get("c", 0) or 0)
                    vol    = float(daily.get("v", 0) or 0)
                    prev_v = float(prev.get("v", 0) or 0)
                    if price <= 0 or prev_c <= 0:
                        continue
                    chg_pct = (price - prev_c) / prev_c * 100
                    # Estimate volume ratio: today's volume vs prev day (same time adjustment)
                    # Not perfect, but good enough for Phase 0 filter
                    vol_ratio_est = (vol / prev_v) if prev_v > 0 else 1.0
                    result[sym] = {
                        "price":         price,
                        "prev_close":    prev_c,
                        "chg_pct":       round(chg_pct, 3),
                        "volume":        vol,
                        "vol_ratio_est": round(vol_ratio_est, 2),
                    }
                except Exception:
                    pass
        except Exception as e:
            logger.debug(f"Alpaca snapshot chunk failed: {e}")
    return result


_ORDER_ENTRY_CACHE: dict = {}

def get_position_entry_times() -> dict:
    """
    Fetch recent filled BUY orders from Alpaca to determine when each position was opened.
    Returns {symbol: filled_at_isostring}. Cached per run.
    """
    global _ORDER_ENTRY_CACHE
    if _ORDER_ENTRY_CACHE:
        return _ORDER_ENTRY_CACHE
    try:
        orders = alpaca_get("/v2/orders?status=closed&limit=200&direction=desc")
        times: dict = {}
        for o in (orders or []):
            sym       = o.get("symbol", "")
            side      = o.get("side", "")
            filled_at = o.get("filled_at") or ""
            if sym and side == "buy" and filled_at and sym not in times:
                times[sym] = filled_at
        _ORDER_ENTRY_CACHE = times
        logger.debug(f"Order entry times loaded for {len(times)} symbols")
    except Exception as e:
        logger.debug(f"Order history fetch failed: {e}")
    return _ORDER_ENTRY_CACHE


# ── Persistence ───────────────────────────────────────────────────────────────
def _load(path, default):
    try:
        return json.loads(path.read_text()) if path.exists() else default
    except Exception:
        return default

class _NumpySafeEncoder(json.JSONEncoder):
    def default(self, obj):
        try:
            import numpy as _np
            if isinstance(obj, _np.integer): return int(obj)
            if isinstance(obj, _np.floating): return float(obj)
            if isinstance(obj, _np.bool_): return bool(obj)
            if isinstance(obj, _np.ndarray): return obj.tolist()
        except ImportError:
            pass
        if hasattr(obj, 'item'): return obj.item()  # any numpy scalar
        return super().default(obj)

def _sanitize_json(obj):
    """Recursively convert any non-JSON-serializable types to native Python."""
    if isinstance(obj, dict):
        return {k: _sanitize_json(v) for k, v in obj.items()}
    if isinstance(obj, (list, tuple)):
        return [_sanitize_json(v) for v in obj]
    # Fast path: native JSON-safe primitives
    if obj is None or obj is True or obj is False:
        return obj
    if type(obj) in (int, float, str):
        return obj
    # numpy/pandas scalars and arrays
    _mod = type(obj).__module__ or ''
    if _mod == 'numpy' or _mod.startswith('numpy.'):
        try: return obj.item()
        except Exception: return str(obj)
    if _mod.startswith('pandas.'):
        try: return str(obj)
        except Exception: return None
    # Any object with .item() (generic numpy-like scalar)
    if hasattr(obj, 'item'):
        try: return obj.item()
        except Exception: return str(obj)
    # datetime/date → ISO string
    if hasattr(obj, 'isoformat'):
        return obj.isoformat()
    # Fallback: if not a known JSON primitive, stringify
    if not isinstance(obj, (int, float, bool, str, type(None))):
        return str(obj)
    return obj

def _save(path, data):
    path.parent.mkdir(exist_ok=True)
    # Three-layer safety: sanitize numpy types, custom encoder, fallback default=str
    try:
        path.write_text(json.dumps(_sanitize_json(data), indent=2))
    except TypeError:
        try:
            path.write_text(json.dumps(data, indent=2, cls=_NumpySafeEncoder))
        except TypeError:
            path.write_text(json.dumps(data, indent=2, default=str))


def _save_equity_snapshot(tlog: dict) -> None:
    """Append daily portfolio snapshot to equity.json with Sharpe, drawdown, and daily P&L stats."""
    try:
        import math as _emath
        pv = float(tlog.get("portfolio_value", 0))
        if pv <= 0:
            return
        eq = _load(EQUITY_FILE, {"snapshots": [], "start_value": 0})
        snaps = eq.get("snapshots", [])
        today = datetime.now(timezone.utc).strftime("%Y-%m-%d")
        # Compute daily P&L vs prior snapshot
        _prior_val = snaps[-1]["value"] if snaps else pv
        _daily_pnl_usd = round(pv - _prior_val, 2)
        _daily_pnl_pct = round((_daily_pnl_usd / _prior_val * 100) if _prior_val else 0, 3)
        # Current open P&L from positions
        _open_pnl_usd = sum(float(p.get("pnl_usd", 0)) for p in tlog.get("positions", []))
        # SPY close for benchmark comparison (from already-fetched cache)
        _spy_close_now = 0.0
        try:
            if _SPY_PERF_CACHE and _SPY_PERF_CACHE.get("closes"):
                _spy_close_now = round(float(_SPY_PERF_CACHE["closes"][-1]), 2)
        except Exception:
            pass
        # Update today's entry or append
        if snaps and snaps[-1].get("date") == today:
            snaps[-1]["value"] = round(pv, 2)
            snaps[-1]["ts"] = datetime.now(timezone.utc).isoformat()
            snaps[-1]["open_pnl"] = round(_open_pnl_usd, 2)
            snaps[-1]["positions"] = len(tlog.get("positions", []))
            if _spy_close_now > 0:
                snaps[-1]["spy_close"] = _spy_close_now
        else:
            _new_snap = {
                "date": today, "value": round(pv, 2),
                "ts": datetime.now(timezone.utc).isoformat(),
                "daily_pnl_usd": _daily_pnl_usd,
                "daily_pnl_pct": _daily_pnl_pct,
                "open_pnl": round(_open_pnl_usd, 2),
                "positions": len(tlog.get("positions", [])),
            }
            if _spy_close_now > 0:
                _new_snap["spy_close"] = _spy_close_now
            snaps.append(_new_snap)
        # Record start value on first snapshot (including SPY start for benchmark)
        if not eq.get("start_value"):
            eq["start_value"]     = round(pv, 2)
            eq["start_date"]      = today
            if _spy_close_now > 0:
                eq["spy_start"] = _spy_close_now
        # Keep 365 days
        eq["snapshots"] = snaps[-365:]
        values = [s["value"] for s in eq["snapshots"]]
        eq["peak_value"]       = max(values)
        eq["current_value"]    = round(pv, 2)
        eq["total_return_pct"] = round((pv / eq["start_value"] - 1) * 100, 2) if eq["start_value"] else 0
        # Max drawdown from peak
        _running_max = values[0]
        _max_dd = 0.0
        for v in values:
            _running_max = max(_running_max, v)
            _dd = (_running_max - v) / _running_max * 100 if _running_max > 0 else 0
            _max_dd = max(_max_dd, _dd)
        eq["max_drawdown_pct"] = round(_max_dd, 2)
        # Sharpe ratio (annualised, risk-free=4.5%)
        if len(snaps) >= 5:
            _rets = []
            for i in range(1, len(snaps)):
                _pv_i   = snaps[i]["value"]
                _pv_im1 = snaps[i-1]["value"]
                if _pv_im1 > 0:
                    _rets.append((_pv_i - _pv_im1) / _pv_im1)
            if len(_rets) >= 2:
                _rf_daily = 0.045 / 252
                _excess = [r - _rf_daily for r in _rets]
                _mean_ex = sum(_excess) / len(_excess)
                _std_ex  = (_emath.sqrt(sum((r - _mean_ex)**2 for r in _excess) / max(1, len(_excess) - 1))) if len(_excess) > 1 else 1e-6
                eq["sharpe_ratio"] = round((_mean_ex / max(_std_ex, 1e-6)) * _emath.sqrt(252), 2)
        # Win rate from daily returns
        _daily_rets = [s.get("daily_pnl_pct", 0) for s in snaps if s.get("daily_pnl_pct") is not None]
        if _daily_rets:
            _wins_d = sum(1 for r in _daily_rets if r > 0)
            eq["daily_win_rate"] = round(_wins_d / len(_daily_rets) * 100, 1)
        # ── SPY benchmark: track SPY alongside portfolio for alpha/benchmark chart ──
        try:
            _spy_cls = _fetch_spy_perf().get("closes", [])
            if _spy_cls:
                _spy_now = float(_spy_cls[-1])
                # Save spy_close on today's snapshot (used by equity chart)
                if snaps:
                    snaps[-1]["spy_close"] = round(_spy_now, 2)
                # Record SPY start price when we first start tracking
                if not eq.get("spy_start") and _spy_cls:
                    eq["spy_start"] = round(_spy_now, 2)
                    eq["spy_start_date"] = today
                eq["spy_current"] = round(_spy_now, 2)
                if eq.get("spy_start"):
                    eq["spy_return_pct"] = round((_spy_now / eq["spy_start"] - 1) * 100, 2)
                    eq["alpha_pct"] = round(eq.get("total_return_pct", 0) - eq.get("spy_return_pct", 0), 2)
        except Exception:
            pass
        _save(EQUITY_FILE, eq)
    except Exception:
        pass


def _save_prices_json(tlog: dict, live: dict | None = None) -> None:
    """Write docs/prices.json with live prices for every position + major indices.
    This is the primary price source for the GitHub Pages site — replaces CORS-blocked
    Yahoo Finance browser calls with bot-side fetches committed every 5 minutes.
    Index ETFs (SPY/QQQ/DIA/IWM/VIX) are ALWAYS fetched and written first.
    """
    try:
        # Start FRESH each run — only keep index ETFs + positions (avoid stale scan garbage)
        now_iso = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        fresh: dict = {}

        # ── Index ETFs — ALWAYS fetch regardless of SPY cache state ──────────
        try:
            import yfinance as _yf_px
            _idx_tickers = ["SPY", "QQQ", "DIA", "IWM"]
            _idx_df = _yf_px.download(
                _idx_tickers, period="5d", interval="1d",
                auto_adjust=True, progress=False, group_by="ticker", threads=False
            )
            for _tk in _idx_tickers:
                try:
                    if hasattr(_idx_df.columns, "levels"):
                        _closes_s = _idx_df[_tk]["Close"].dropna()
                    else:
                        _closes_s = _idx_df["Close"].dropna()
                    if len(_closes_s) >= 1:
                        _px   = float(_closes_s.iloc[-1])
                        _prev = float(_closes_s.iloc[-2]) if len(_closes_s) >= 2 else _px
                        _chg  = round((_px - _prev) / _prev * 100, 2) if _prev else 0
                        fresh[_tk] = {"price": round(_px, 2), "change_pct": _chg, "updated": now_iso}
                except Exception:
                    pass
        except Exception:
            pass

        # ── VIX ───────────────────────────────────────────────────────────────
        try:
            import yfinance as _yf_vix
            _vix_data = _yf_vix.download("^VIX", period="5d", interval="1d",
                                          auto_adjust=True, progress=False, threads=False)
            _vix_cls = _vix_data["Close"].dropna() if not _vix_data.empty else []
            if len(_vix_cls) >= 1:
                _vix_val  = float(_vix_cls.iloc[-1])
                _vix_prev = float(_vix_cls.iloc[-2]) if len(_vix_cls) >= 2 else _vix_val
                _vix_chg  = round((_vix_val - _vix_prev) / _vix_prev * 100, 2) if _vix_prev else 0
                fresh["^VIX"] = {"price": round(_vix_val, 2), "change_pct": _vix_chg, "updated": now_iso}
                fresh["VIX"]  = fresh["^VIX"]
        except Exception:
            pass

        # ── Current Alpaca positions (real market prices from Alpaca API) ─────
        for pos in tlog.get("positions", []):
            tk = pos.get("ticker")
            if not tk:
                continue
            fresh[tk] = {
                "price":      round(float(pos.get("price", 0) or 0), 2),
                "change_pct": round(float(pos.get("pnl_pct", 0) or 0), 2),
                "updated":    now_iso,
            }

        # ── Live signal data (scan universe) — only top-scored stocks ─────────
        if live:
            for tk, sig in live.items():
                if not tk or not sig or len(tk) > 5:   # skip malformed tickers
                    continue
                _p = float(sig.get("price", 0) or 0)
                _c = float(sig.get("chg_pct", 0) or 0)
                if _p > 0 and tk not in fresh:
                    fresh[tk] = {"price": round(_p, 2), "change_pct": round(_c, 2), "updated": now_iso}

        _save(PRICES_FILE, fresh)
        _idx_found = [k for k in ("SPY","QQQ","DIA","IWM","^VIX") if k in fresh]
        logger.info(f"prices.json: {len(fresh)} tickers, indices={_idx_found}")
    except Exception as _pe:
        logger.debug(f"prices.json save failed: {_pe}")


def log_trade(tlog, action, sym, price, amount, score=None, pnl=None, reason=None, signals=None):
    pnl_pct = pnl  # alias so neuron update blocks (which use pnl_pct) work correctly
    # Cache the matching BUY record once — eliminates 867 redundant O(n) scans inside SELL blocks
    _cached_buy_rec = (
        next((t for t in reversed(tlog.get("trades", []))
              if t.get("action") == "BUY" and t.get("ticker") == sym), None)
        if action in ("SELL", "SELL_HALF", "COVER") else None
    )
    e = {
        "time":    datetime.now(timezone.utc).isoformat(),
        "action":  action,
        "ticker":  sym,
        "price":   round(float(price), 2),
        "score":   score,
        "pnl_pct": round(float(pnl), 2) if pnl is not None else None,
        "reason":  reason,
    }
    if action in ("BUY", "SHORT"):
        e["notional"] = round(float(amount), 2)
    else:
        e["qty"] = float(amount)

    # Store catalyst type and sector at entry for performance attribution
    if action == "BUY" and signals:
        e["catalyst_type"] = signals.get("catalyst_type", "none")
        e["sector"] = SECTOR_MAP.get(sym, "other")
        # Store current regime at entry so we can analyze regime-based performance later
        _cur_regime = tlog.get("regime", {})
        e["regime"] = _cur_regime.get("regime", "unknown") if isinstance(_cur_regime, dict) else str(_cur_regime)[:20]
        # Store VIX at entry for VIX-bracket performance tracking
        _vix_entry = None
        if isinstance(_cur_regime, dict): _vix_entry = _cur_regime.get("vix")
        if _vix_entry is not None: e["vix_at_entry"] = round(float(_vix_entry), 1)
        # Store additional entry context for performance attribution neurons
        e["rvol_at_entry"]        = round(float(signals.get("rvol", 1.0) or 1.0), 2)
        e["earnings_days_at_entry"] = signals.get("earnings_days")  # None if unknown
        e["mkt_quality_at_entry"]  = int(tlog.get("market_quality", 50) or 50)
        # Portfolio concentration at entry (# held positions when we bought)
        _n_held = len([t for t in tlog.get("trades", []) if t.get("action") == "BUY"
                       and not any(s.get("ticker") == t.get("ticker") and s.get("action") in ("SELL","SELL_HALF","COVER")
                                   for s in tlog.get("trades", []) if s.get("time", "") > t.get("time", ""))])
        e["positions_at_entry"] = max(0, _n_held)
        e["concentration_bucket"] = ("1-2" if _n_held <= 2 else "3-4" if _n_held <= 4 else "5-7" if _n_held <= 7 else "8+")
        # Day of week at entry (0=Mon, 6=Sun)
        _dow = datetime.now(timezone.utc).weekday()
        e["day_of_week"] = _dow
        e["day_name"] = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"][_dow]
        e["entry_dow"] = ["monday","tuesday","wednesday","thursday","friday","saturday","sunday"][_dow]
        # Breadth at entry (% sectors/stocks advancing)
        _breadth_entry = tlog.get("market_breadth", {})
        e["breadth_at_entry"] = round(float(_breadth_entry.get("adv_pct", 50) or 50), 1)
        # Momentum grade at entry (A+/A/B/C/D) — compute here using score + signals
        try:
            e["grade_at_entry"] = momentum_grade(signals, score or 0)
        except Exception:
            e["grade_at_entry"] = "?"
        # Price tier at entry
        _p = float(price)
        e["price_tier"] = ("micro" if _p < 10 else "small" if _p < 30 else "mid" if _p < 100 else "large")
        # Macro event context at entry (FOMC/CPI/NFP awareness)
        try:
            _macro_ctx = get_macro_context()
            e["macro_event"] = _macro_ctx["event"]    # "FOMC", "CPI", "NFP", "none"
            e["macro_label"] = _macro_ctx["label"]    # "event_day", "day_before", "normal"
        except Exception:
            e["macro_event"] = "none"
            e["macro_label"] = "normal"
        # RSI at entry (daily RSI for swing entry quality tracking)
        e["rsi_at_entry"] = round(float(signals.get("daily_rsi", 50) or 50), 1)
        # Score trend at entry: was score rising/flat/falling across recent scans?
        e["score_trend"] = signals.get("score_trend", "flat")
        e["score_trend_delta"] = float(signals.get("score_trend_delta", 0.0) or 0.0)
        # Position size and ATR distance at entry (for Neurons 28 and 29)
        e["pos_size_pct"]    = float(signals.get("pos_size_pct", 0.0) or 0.0)
        e["pos_size_bucket"] = signals.get("pos_size_bucket", "2-5%")
        e["atr_pct_at_entry"] = float(signals.get("atr_pct_at_entry", 0.0) or 0.0)
        e["atr_bucket"]      = signals.get("atr_bucket", "1-2%")
        # Pre-market gap at entry (Neuron 30)
        _pm_gap = float(signals.get("pm_gap_pct", 0.0) or 0.0)
        e["pm_gap_pct"] = round(_pm_gap, 1)
        e["pm_gap_bucket"] = ("big_up" if _pm_gap > 3 else "small_up" if _pm_gap > 0.5 else
                              "big_down" if _pm_gap < -3 else "small_down" if _pm_gap < -0.5 else "flat")
        # Sector momentum at entry (Neuron 32): was the sector ETF accelerating?
        try:
            _sec_etf_now = tlog.get("sector_etf_trends", {}).get(SECTOR_MAP.get(sym, "other"), {})
            _sec_chg1d = float(_sec_etf_now.get("chg1d", 0.0) or 0.0)
            _sec_chg5d = float(_sec_etf_now.get("chg5d", 0.0) or 0.0)
            _sec_momentum = ("accelerating" if _sec_chg1d > 0.5 and _sec_chg5d > 1.0 else
                             "decelerating" if _sec_chg1d < -0.3 and _sec_chg5d < 0 else "neutral")
            e["sector_etf_momentum"] = _sec_momentum
            e["sector_chg1d"] = round(_sec_chg1d, 2)
        except Exception:
            e["sector_etf_momentum"] = "neutral"
        # Trend Template Neuron (33): O'Neil quality score at entry
        _tt_score = int(signals.get("trend_template", 0) or 0)
        e["tt_score_at_entry"] = _tt_score
        e["tt_bucket"] = ("elite" if _tt_score >= 7 else "good" if _tt_score >= 5 else "fair" if _tt_score >= 3 else "weak")
        # Consecutive Green Days Neuron (34): momentum confirmation days
        _cg = int(signals.get("consec_green", 0) or 0)
        e["consec_green_at_entry"] = _cg
        e["consec_green_bucket"] = ("0d" if _cg == 0 else "1d" if _cg == 1 else "2-3d" if _cg <= 3 else "4d+")
        # Institutional Accumulation Neuron (35): smart money accumulation score
        _ac = int(signals.get("accum_score", 0) or 0)
        e["accum_score_at_entry"] = _ac
        e["accum_bucket"] = ("heavy" if _ac >= 8 else "moderate" if _ac >= 5 else "light" if _ac >= 2 else "none")
        # RS Rating Neuron (36): IBD-style Relative Strength Rating at entry
        _rs_r = int(signals.get("rs_rating", 50) or 50)
        e["rs_rating_at_entry"] = _rs_r
        e["rs_bucket"] = ("elite" if _rs_r >= 90 else "strong" if _rs_r >= 75 else "average" if _rs_r >= 50 else "weak")
        # MACD Neuron (37): MACD state at entry (bullish cross, positive, negative, divergence)
        _macd_v = float(signals.get("macd", 0.0) or 0.0)
        _macd_s = float(signals.get("macd_slope", 0.0) or 0.0)
        _macd_d = bool(signals.get("macd_bull_div", False))
        e["macd_state"] = ("bull_div" if _macd_d else "rising" if _macd_v > 0 and _macd_s > 0 else
                           "recovering" if _macd_v < 0 and _macd_s > 0 else "negative")
        # TTM Squeeze Breakout Neuron (38): was a squeeze fired at entry?
        e["squeeze_fired"] = bool(signals.get("ttm_squeeze_fired", False))
        # News Catalyst Urgency Neuron (39): urgency score 0-5 from AI catalyst classification
        _urg = int(signals.get("catalyst_urg", 0) or 0)
        e["catalyst_urgency"] = _urg
        e["urgency_bucket"] = ("high" if _urg >= 4 else "medium" if _urg >= 2 else "low")
        # VWAP Position Neuron (40): was price above/below VWAP at entry?
        _vwap_p = float(signals.get("vwap_pos", 0.0) or 0.0)
        e["vwap_pos_at_entry"] = round(_vwap_p, 2)
        e["vwap_bucket"] = ("above" if _vwap_p > 0.5 else "below" if _vwap_p < -0.5 else "at_vwap")
        # POC Distance Neuron (42): how far above/below Point of Control at entry?
        # POC = price level with most volume traded = institutional anchor price.
        # Breakout entries (well above POC) = smart money control; below = risky.
        _poc_pr = float(signals.get("poc_price", 0.0) or 0.0)
        _entry_pr = float(price if price else 0.0)
        if _poc_pr > 0 and _entry_pr > 0:
            _poc_dist = round((_entry_pr - _poc_pr) / _poc_pr * 100, 2)
            e["poc_dist_pct"] = _poc_dist
            e["poc_dist_bucket"] = ("breakout" if _poc_dist > 2.0 else "above" if _poc_dist > 0.5
                                    else "at_poc" if _poc_dist >= -0.5 else "below")
        else:
            e["poc_dist_pct"] = 0.0
            e["poc_dist_bucket"] = "at_poc"
        # Intraday Momentum Neuron (43): how far from today's open at entry?
        # Stocks up 5%+ from open may be extended (chasing); flat to +2% = ideal momentum.
        # Learns: does buying early (near open) outperform chasing intraday runners?
        _d_open = float(signals.get("day_open", 0.0) or 0.0)
        if _d_open > 0 and _entry_pr > 0:
            _id_mom = round((_entry_pr - _d_open) / _d_open * 100, 2)
            e["intraday_mom_pct"] = _id_mom
            e["intraday_mom_bucket"] = ("extended" if _id_mom > 5.0 else "runner" if _id_mom > 2.0
                                        else "early" if _id_mom >= 0.0 else "pullback")
        else:
            e["intraday_mom_pct"] = 0.0
            e["intraday_mom_bucket"] = "early"
        # ADX Trend Strength Neuron (44): directional trend conviction at entry.
        # ADX >25 = strong trend (momentum algos' sweet spot), 15-25 = developing,
        # <15 = no trend / choppy — high risk for directional strategies.
        _adx_v = float(signals.get("adx", 0.0) or 0.0)
        e["adx_at_entry"] = round(_adx_v, 1)
        e["adx_bucket"] = ("strong" if _adx_v >= 25 else "developing" if _adx_v >= 15 else "weak")
        # RVOL Tier Neuron (45): actual relative volume ratio at entry.
        # 5x+ = explosive institutional interest, 2-5x = strong, 1-2x = normal, <1x = weak.
        # More granular than the binary rvol_surge signal — learns the optimal RVOL tier.
        _rvol_v = float(signals.get("rvol", 0.0) or 0.0)
        e["rvol_at_entry"] = round(_rvol_v, 2)
        e["rvol_tier"] = ("explosive" if _rvol_v >= 5.0 else "strong" if _rvol_v >= 2.0
                          else "normal" if _rvol_v >= 1.0 else "weak")
        # Stochastic Zone Neuron (46): %K at entry — overbought/neutral/oversold zone.
        # Overbought (>80) entries are late momentum chases; neutral (20-80) is the sweet spot;
        # oversold (<20) = mean reversion entry — learns which zone produces best outcomes.
        _stk_v = float(signals.get("stoch_k", 50.0) or 50.0)
        e["stoch_k_at_entry"] = round(_stk_v, 1)
        e["stoch_zone"] = ("overbought" if _stk_v > 80 else "oversold" if _stk_v < 20 else "neutral")
        # Multi-Timeframe Alignment Neuron (47): are short/medium/long timeframes all aligned?
        # full = mtf_aligned + ema_stacked_bull + ROC20>0 (all three agree = highest conviction).
        # partial = at least one confirmed. none = mixed or bearish signals.
        _mtf_ok = bool(signals.get("mtf_aligned", False))
        _ema_bull = bool(signals.get("ema_stacked_bull", False))
        _roc20_v = float(signals.get("roc20", 0.0) or 0.0)
        _mtf_score = int(_mtf_ok) + int(_ema_bull) + int(_roc20_v > 0)
        e["mtf_score_at_entry"] = _mtf_score
        e["mtf_alignment"] = ("full" if _mtf_score >= 3 else "partial" if _mtf_score >= 1 else "none")
        # Options Flow Neuron (48): smart money positioning at entry.
        # unusual_calls + options_bull + low PCR (<0.7) = institutional call buying.
        # Learns: do entries confirmed by options flow outperform unconfirmed entries?
        _uc = bool(signals.get("unusual_calls", False))
        _ob = bool(signals.get("options_bull", False))
        _pcr = float(signals.get("options_pcr", 1.0) or 1.0)
        _opt_score = int(_uc) + int(_ob) + int(_pcr < 0.7)
        e["options_flow_score"] = _opt_score
        e["options_flow_tier"] = ("confirmed" if _opt_score >= 2 else "slight" if _opt_score >= 1 else "neutral")
        # MFI Zone Neuron (49): Money Flow Index at entry (volume-weighted RSI).
        # MFI >80 = heavy distribution (overbought + volume selling); <20 = accumulation.
        # More reliable than RSI because it incorporates volume — harder to fake.
        _mfi_v = float(signals.get("mfi", 50.0) or 50.0)
        e["mfi_at_entry"] = round(_mfi_v, 1)
        e["mfi_zone"] = ("distribution" if _mfi_v > 80 else "accumulation" if _mfi_v < 30 else "neutral")
        # Williams %R Neuron (50): momentum oscillator confirming trend strength.
        # W%R > -20 = overbought (danger: rally may be exhausted); < -80 = oversold.
        # -80 to -20 = trending zone (ideal for momentum entries).
        _wr_v = float(signals.get("williams_r", -50.0) or -50.0)
        e["williams_r_at_entry"] = round(_wr_v, 1)
        e["wr_zone"] = ("overbought" if _wr_v > -20 else "oversold" if _wr_v < -80 else "trending")
        # Ichimoku Cloud Neuron (51): cloud position at entry — institutional trend system.
        # above = above cloud (strong bull trend, institutions own it).
        # cloud = inside cloud (transition, uncertainty — high failure risk).
        # below = below cloud (bearish — avoid unless contrarian with tight stop).
        _ichi_above = bool(signals.get("ichimoku_above", False))
        _ichi_bull  = bool(signals.get("ichimoku_bull_cloud", False))
        _ichi_tk    = bool(signals.get("ichimoku_tk_bull", False))
        _ichi_score = int(_ichi_above) + int(_ichi_bull) + int(_ichi_tk)
        e["ichimoku_score_at_entry"] = _ichi_score
        e["ichimoku_position"] = ("above" if _ichi_above else "inside" if _ichi_bull else "below")
        # Linear Regression Quality Neuron (52): R² measures how well price fits a trend line.
        # R² > 0.85 = very clean trend (high conviction setup); 0.6-0.85 = moderate;
        # < 0.6 = choppy/noisy (unreliable trend — high failure risk for directional plays).
        _lr_r2 = float(signals.get("lr_r2", 0.0) or 0.0)
        _lr_slope = float(signals.get("lr_slope", 0.0) or 0.0)
        e["lr_r2_at_entry"] = round(_lr_r2, 3)
        e["lr_slope_at_entry"] = round(_lr_slope, 4)
        e["lr_quality"] = ("strong" if _lr_r2 >= 0.85 else "moderate" if _lr_r2 >= 0.6 else "weak")
        # Donchian Channel Position Neuron (53): is price at a 20-day high (breakout)?
        # donchian_pct = price position within 20-day range (0=low, 100=high).
        # Upper quartile (>75%) = breakout territory; lower (<25%) = weakness.
        _dc_pct = float(signals.get("donchian_pct", 50.0) or 50.0)
        e["donchian_pct_at_entry"] = round(_dc_pct, 1)
        e["donchian_zone"] = ("breakout" if _dc_pct >= 75 else "middle" if _dc_pct >= 25 else "weakness")
        # Heikin Ashi Trend Neuron (54): HA candles smooth noise and show trend clarity.
        # HA bull = smoothed uptrend (high quality momentum signal); HA bear = distribution.
        # Learns: do HA-confirmed bullish entries produce better outcomes?
        _ha_bull = bool(signals.get("ha_bull", False))
        e["ha_bull_at_entry"] = _ha_bull
        e["ha_trend"] = ("bull" if _ha_bull else "bear")
        # Keltner Channel Position Neuron (55): is price at KC breakout or oversold bounce?
        # kc_pos = price % position in Keltner Channel. breakout = price above KC upper band.
        # kc_oversold = price below lower band. Learns: breakout vs bounce entries.
        _kc_brk = bool(signals.get("kc_breakout", False))
        _kc_pos = float(signals.get("kc_pos", 50.0) or 50.0)
        e["kc_pos_at_entry"] = round(_kc_pos, 1)
        e["kc_zone"] = ("breakout" if _kc_brk or _kc_pos >= 80 else "oversold" if _kc_pos <= 20 else "inside")
        # OBV Trend Neuron (56): On Balance Volume trend at entry.
        # OBV rising = volume confirming price uptrend (institutions buying).
        # OBV falling while price flat/up = distribution (smart money exiting quietly).
        _obv_rise = bool(signals.get("obv_rising", False))
        e["obv_rising_at_entry"] = _obv_rise
        e["obv_trend"] = ("rising" if _obv_rise else "falling")
        # Force Index Neuron (57): Elder's Force Index at entry.
        # fi_rising + fi_bull_div = price moving with increasing force (acceleration confirmed).
        # fi_div (divergence) = price going up but force weakening = distribution warning.
        _fi_rising = bool(signals.get("force_index_rising", False))
        _fi_div = bool(signals.get("force_index_div", False))
        _fi_score = int(_fi_rising) + int(_fi_div) * 2  # div is more bullish than just rising
        e["force_index_score"] = _fi_score
        e["force_index_state"] = ("bull_div" if _fi_div else "rising" if _fi_rising else "weak")
        # Price Acceleration Neuron (58): is price momentum accelerating upward at entry?
        # price_accel_pos = price moving faster than its recent rate (breakout momentum).
        # Learns: do acceleration-confirmed entries produce bigger wins?
        _pa = bool(signals.get("price_accel_pos", False))
        e["price_accel_at_entry"] = _pa
        e["price_accel_state"] = ("accelerating" if _pa else "decelerating")
        # Gap-and-Hold Neuron (59): stock gapped up AND is holding above the gap.
        # Gap-and-hold = institutional accumulation; gap-and-fill = distribution/trap.
        # Learns: do gap-and-hold entries (confirms institutional buyers) produce better returns?
        _gah = bool(signals.get("gap_and_hold", False))
        e["gap_and_hold_at_entry"] = _gah
        e["gap_hold_state"] = ("holding" if _gah else "normal")
        # Opening Range Breakout Neuron (60): classic first-30-min range breakout.
        # Price breaks above the first 30 minutes range = trend for the day is set.
        # Learns: do ORB entries (clear directional intent) produce more consistent wins?
        _orb = bool(signals.get("orb_breakout", False))
        e["orb_at_entry"] = _orb
        e["orb_state"] = ("breakout" if _orb else "consolidating")

        # Supertrend + PSAR Neuron (61): trend-following confirmation layer
        _st_bull = bool(signals.get("supertrend_bull", False))
        _ps_bull = bool(signals.get("psar_bull", False))
        _trend_conf_score = int(_st_bull) + int(_ps_bull)
        e["supertrend_at_entry"] = _st_bull
        e["psar_at_entry"] = _ps_bull
        e["trend_conf_score"] = _trend_conf_score
        e["trend_conf_state"] = ("both" if _trend_conf_score == 2 else "one" if _trend_conf_score == 1 else "neither")

        # Bollinger Band Position Neuron (62): where is price within the bands?
        _bb_pos_v = float(signals.get("bb_pos", 50.0) or 50.0)
        e["bb_pos_at_entry"] = round(_bb_pos_v, 1)
        e["bb_zone"] = ("upper" if _bb_pos_v >= 80 else "lower" if _bb_pos_v <= 20 else "mid")

        # Candle Pattern Score Neuron (63): bullish candle patterns at entry
        _hammer = bool(signals.get("hammer", False))
        _mstar  = bool(signals.get("morning_star", False))
        _tws    = bool(signals.get("three_white_soldiers", False))
        _beng   = bool(signals.get("bullish_engulfing", False))
        _candle_score = int(_hammer) + int(_mstar) + int(_tws) + int(_beng)
        e["candle_score_at_entry"] = _candle_score
        e["candle_state"] = ("strong" if _candle_score >= 2 else "present" if _candle_score == 1 else "none")

        # Volume Dry-Up Neuron (64): low-vol consolidation before breakout
        _vdu = bool(signals.get("vol_dry_up", False))
        e["vol_dry_up_at_entry"] = _vdu
        e["vol_dry_state"] = ("dry_up" if _vdu else "normal_vol")

        # Chart Pattern Score Neuron (65): classic breakout chart patterns
        _bf  = bool(signals.get("bull_flag", False))
        _ch  = bool(signals.get("cup_handle", False))
        _vcp = bool(signals.get("vcp", False))
        _pp  = bool(signals.get("pocket_pivot", False))
        _chart_score = int(_bf) + int(_ch) + int(_vcp) + int(_pp)
        e["chart_pattern_score"] = _chart_score
        e["chart_pattern_state"] = ("multi" if _chart_score >= 2 else "single" if _chart_score == 1 else "none")

        # ROC Momentum Neuron (66): rate of change on 5-day and 20-day windows
        _roc5_v  = float(signals.get("roc5", 0.0) or 0.0)
        _roc20_v = float(signals.get("roc20", 0.0) or 0.0)
        e["roc5_at_entry"]  = round(_roc5_v, 2)
        e["roc20_at_entry"] = round(_roc20_v, 2)
        _roc_state = ("accelerating" if _roc5_v > 0 and _roc20_v > 0 and _roc5_v > _roc20_v
                      else "positive" if _roc5_v > 0 or _roc20_v > 0
                      else "negative")
        e["roc_state"] = _roc_state

        # Relative Strength Momentum Neuron (67): RS5 vs RS63 (short vs long)
        _rs5_v  = float(signals.get("rs5", 0.0) or 0.0)
        _rs63_v = float(signals.get("rs63", 0.0) or 0.0)
        e["rs5_at_entry"]  = round(_rs5_v, 2)
        e["rs63_at_entry"] = round(_rs63_v, 2)
        _rs_mom_state = ("leading" if _rs5_v > 1.0 and _rs63_v > 1.0
                         else "improving" if _rs5_v > _rs63_v
                         else "lagging")
        e["rs_mom_state"] = _rs_mom_state

        # Demand Zone Proximity Neuron (68): at/near institutional demand
        _at_dz  = bool(signals.get("at_demand_zone", False))
        _near_s = bool(signals.get("near_support", False))
        _fib_s  = bool(signals.get("fib_support", False))
        _dz_score = int(_at_dz) + int(_near_s) + int(_fib_s)
        e["demand_zone_score"] = _dz_score
        e["demand_zone_state"] = ("at_zone" if _at_dz else "near_zone" if _dz_score >= 1 else "no_zone")

        # Higher Lows Pattern Neuron (69): ascending support = institutional accumulation
        _hl = bool(signals.get("higher_lows", False))
        e["higher_lows_at_entry"] = _hl
        e["higher_lows_state"] = ("confirmed" if _hl else "not_confirmed")

        # HA Consecutive Bull Neuron (70): how many consecutive green Heikin Ashi candles
        _ha_consec = int(signals.get("ha_consec_bull", 0) or 0)
        e["ha_consec_at_entry"] = _ha_consec
        e["ha_consec_state"] = ("strong" if _ha_consec >= 4 else "building" if _ha_consec >= 2 else "early")

        # NR7 Signal Neuron (71): narrowest range in 7 days = volatility compression before explosion
        _nr7 = bool(signals.get("nr7_signal", False))
        e["nr7_at_entry"] = _nr7
        e["nr7_state"] = ("compressed" if _nr7 else "normal_range")

        # EMA Structure Neuron (72): price vs EMA50 and EMA200 = trend health
        _above_ema50  = bool(signals.get("price_vs_ema50", False))
        _above_ema200 = bool(signals.get("price_vs_ema200", False))
        _ema_struct_score = int(_above_ema50) + int(_above_ema200)
        e["ema_struct_score"] = _ema_struct_score
        e["ema_struct_state"] = ("both" if _ema_struct_score == 2 else "ema50_only" if _above_ema50 else "below_both")

        # MACD Divergence Neuron (73): bullish divergence = hidden accumulation
        _macd_div = bool(signals.get("macd_bull_div", False))
        e["macd_div_at_entry"] = _macd_div
        e["macd_div_state"] = ("diverging" if _macd_div else "no_div")

        # MFI Divergence Neuron (74): MFI bull div = money flowing in against price drop
        _mfi_div = bool(signals.get("mfi_bull_div", False))
        e["mfi_div_at_entry"] = _mfi_div
        e["mfi_div_state"] = ("diverging" if _mfi_div else "no_div")

        # Vol Ratio + Momentum Combo Neuron (75): volume ratio confirms momentum acceleration
        _vol_ratio_v = float(signals.get("vol_ratio", 1.0) or 1.0)
        _mom_acc = bool(signals.get("mom_accel", False))
        e["vol_ratio_at_entry"] = round(_vol_ratio_v, 2)
        e["vol_ratio_mom_state"] = ("confirmed" if _vol_ratio_v >= 1.5 and _mom_acc
                                    else "partial" if _vol_ratio_v >= 1.2 or _mom_acc
                                    else "weak")

        # Double Bottom Neuron (76): classic reversal pattern at support
        _db = bool(signals.get("double_bottom", False))
        e["double_bottom_at_entry"] = _db
        e["double_bottom_state"] = ("confirmed" if _db else "none")

        # At-Breakout Level Neuron (77): price exactly at key breakout = low risk entry
        _atb = bool(signals.get("at_breakout", False))
        e["at_breakout_at_entry"] = _atb
        e["at_breakout_state"] = ("at_level" if _atb else "not_at_level")

        # Above AVWAP-52WL Neuron (78): above anchored VWAP from 52wk low = bullish bias
        _avwap = bool(signals.get("above_avwap_52wl", False))
        e["above_avwap_at_entry"] = _avwap
        e["avwap_state"] = ("above" if _avwap else "below")

        # Above POC Neuron (79): price above volume point-of-control = buyers in control
        _apoc = bool(signals.get("above_poc", False))
        e["above_poc_at_entry"] = _apoc
        e["poc_control_state"] = ("above" if _apoc else "below")

        # Pre-Market Big Gap-Up Neuron (80): overnight institutional conviction
        _pmgap = bool(signals.get("pm_big_gap_up", False))
        _pmgap_pct = float(signals.get("pm_gap_pct", 0.0) or 0.0)
        e["pm_big_gap_at_entry"] = _pmgap
        e["pm_gap_pct_at_entry"] = round(_pmgap_pct, 2)
        e["pm_gap_state"] = ("big" if _pmgap and _pmgap_pct >= 2.0 else "small_gap" if _pmgap_pct > 0.5 else "flat")

        # HTF Confirmation Neuron (81): higher timeframe trend alignment
        _htf = bool(signals.get("htf", False))
        e["htf_at_entry"] = _htf
        e["htf_state"] = ("aligned" if _htf else "not_aligned")

        # EMA21 Pullback Neuron (82): pulling back to fast EMA = second-chance entry
        _ema21pb = bool(signals.get("ema21_pullback", False))
        e["ema21_pb_at_entry"] = _ema21pb
        e["ema21_pb_state"] = ("pullback" if _ema21pb else "extended")

        # MTF Triple Neuron (83): three-timeframe perfect alignment (tighter signal)
        _mtf3 = bool(signals.get("mtf_triple", False))
        e["mtf_triple_at_entry"] = _mtf3
        e["mtf_triple_state"] = ("triple" if _mtf3 else "partial_or_none")

        # RS63 (Quarterly RS) Neuron (84): leading stocks consistently outperform
        _rs63q = float(signals.get("rs63", 0.0) or 0.0)
        e["rs63_q_at_entry"] = round(_rs63q, 2)
        e["rs63_q_tier"] = ("elite" if _rs63q >= 1.5 else "leading" if _rs63q >= 1.0 else "average" if _rs63q >= 0.5 else "lagging")

        # Squeeze Potential Neuron (85): coiled but not fired = get in before the move
        _sqpot = bool(signals.get("squeeze_potential", False))
        e["sq_potential_at_entry"] = _sqpot
        e["sq_potential_state"] = ("coiled" if _sqpot else "not_coiled")

        # News Count 24h Neuron (86): volume of news = catalyst heat
        _nc24 = int(signals.get("news_count_24h", 0) or 0)
        e["news_count_at_entry"] = _nc24
        e["news_count_tier"] = ("hot" if _nc24 >= 10 else "active" if _nc24 >= 4 else "quiet")

        # News Accelerating Neuron (87): building narrative = momentum play
        _nacc = bool(signals.get("news_accelerating", False))
        e["news_accel_at_entry"] = _nacc
        e["news_accel_state"] = ("accelerating" if _nacc else "steady")

        # True Alpha Neuron (88): independent stock move vs market beta
        _talpha = float(signals.get("true_alpha", 0.0) or 0.0)
        e["true_alpha_at_entry"] = round(_talpha, 3)
        e["true_alpha_tier"] = ("high" if _talpha >= 0.5 else "positive" if _talpha > 0 else "negative")

        # Pivot Support Neuron (89): at S1 or S2 pivot = classic institutional support
        _ps1 = float(signals.get("pivot_s1", 0.0) or 0.0)
        _ps2 = float(signals.get("pivot_s2", 0.0) or 0.0)
        _pr_now = float(signals.get("price", 0.0) or _entry_pr)
        _at_pivot = (_ps1 > 0 and abs(_pr_now - _ps1) / _ps1 < 0.005) or (_ps2 > 0 and abs(_pr_now - _ps2) / _ps2 < 0.005)
        e["at_pivot_support"] = _at_pivot
        e["pivot_state"] = ("at_support" if _at_pivot else "between")

        # VCP Dedicated Neuron (90): Volatility Contraction Pattern — O'Neil setup
        _vcp_v = bool(signals.get("vcp", False))
        e["vcp_at_entry"] = _vcp_v
        e["vcp_state"] = ("vcp" if _vcp_v else "no_vcp")

        # Pocket Pivot Neuron (91): O'Neil pocket pivot = institutional buying surge
        _pocket_piv = bool(signals.get("pocket_pivot", False))
        e["pocket_pivot_at_entry"] = _pocket_piv
        e["pocket_pivot_state"] = ("pivot" if _pocket_piv else "no_pivot")

        # Morning Star Neuron (92): 3-candle bottom reversal pattern
        _morn_star = bool(signals.get("morning_star", False))
        e["morning_star_at_entry"] = _morn_star
        e["morning_star_state"] = ("morning_star" if _morn_star else "none")

        # Three White Soldiers Neuron (93): three consecutive strong bull candles
        _tws_v = bool(signals.get("three_white_soldiers", False))
        e["tws_at_entry"] = _tws_v
        e["tws_state"] = ("three_soldiers" if _tws_v else "none")

        # Bullish Engulfing Neuron (94): engulfing candle at support = reversal
        _beng_v = bool(signals.get("bullish_engulfing", False))
        e["beng_at_entry"] = _beng_v
        e["beng_state"] = ("engulfing" if _beng_v else "none")

        # Hammer Candle Neuron (95): hammer at support = strong rejection of lower prices
        _hammer_v = bool(signals.get("hammer", False))
        e["hammer_at_entry"] = _hammer_v
        e["hammer_state"] = ("hammer" if _hammer_v else "none")

        # Cup-and-Handle Pivot Neuron (96): classic O'Neil cup-and-handle
        _ch_pivot = float(signals.get("cup_handle_pivot", 0.0) or 0.0)
        _ch_v = bool(signals.get("cup_handle", False))
        _ch_at_pivot = _ch_v and _ch_pivot > 0 and abs(_entry_pr - _ch_pivot) / _ch_pivot < 0.02 if _ch_pivot > 0 else _ch_v
        e["cup_handle_at_entry"] = _ch_v
        e["ch_pivot_proximity"] = "at_pivot" if _ch_at_pivot else ("cup_no_pivot" if _ch_v else "none")

        # Double Bottom Neckline Neuron (97): entering at double bottom neckline breakout
        _dbn = bool(signals.get("double_bottom_neckline", False))
        e["dbn_at_entry"] = _dbn
        e["dbn_state"] = ("neckline_break" if _dbn else "below_neck")

        # Earnings Growth Signal Neuron (98): strong EPS growth = fundamental momentum
        _earn_gr = float(signals.get("earnings_growth", 0.0) or 0.0)
        e["earnings_growth_at_entry"] = round(_earn_gr, 1)
        e["eg_tier"] = ("accelerating" if _earn_gr >= 50 else "strong" if _earn_gr >= 25 else "positive" if _earn_gr > 0 else "negative")

        # Supertrend Stop Proximity Neuron (99): how tight is the Supertrend stop?
        _st_stop = float(signals.get("supertrend_stop", 0.0) or 0.0)
        _st_gap_pct = round((_entry_pr - _st_stop) / _entry_pr * 100, 2) if _st_stop > 0 and _entry_pr > 0 else 0.0
        e["st_stop_gap_pct"] = _st_gap_pct
        e["st_gap_tier"] = ("tight" if 0 < _st_gap_pct <= 2.0 else "normal" if _st_gap_pct <= 5.0 else "wide" if _st_gap_pct > 5.0 else "no_st")

        # Signal Combination Score Neuron (100): count of premium signals confirming — the master neuron
        _premium_sigs = [
            bool(signals.get("vcp", False)), bool(signals.get("cup_handle", False)),
            bool(signals.get("at_breakout", False)), bool(signals.get("mtf_triple", False)),
            bool(signals.get("ttm_squeeze_fired", False)),  # gap_and_hold removed: 35%WR n=23 (Wave 99)
            bool(signals.get("orb_breakout", False)), bool(signals.get("rvol_surge", False)),
            bool(signals.get("supertrend_bull", False)), bool(signals.get("obv_rising", False)),
        ]
        _premium_count = sum(_premium_sigs)
        e["premium_signal_count"] = _premium_count
        e["premium_tier"] = ("elite" if _premium_count >= 6 else "strong" if _premium_count >= 4
                              else "normal" if _premium_count >= 2 else "weak")

    # Store active signals at entry for performance tracking
    if action == "BUY" and signals:
        _SIGNAL_KEYS = list(dict.fromkeys([
            "cup_handle", "at_demand_zone", "mom_accel", "vcp", "obv_rising",
            "kc_breakout", "higher_lows", "double_bottom", "poc_breakout",
            "ema_stacked_bull", "trend_reversal", "bull_flag", "mtf_aligned",
            "ttm_squeeze_fired", "at_breakout", "vwap_reclaim", "gap_and_hold",
            "nr7_signal", "fib_support", "macd_bull_div", "rsi_bull_divergence",
            "ichimoku_above", "orb_breakout", "above_poc",
            "rvol_surge", "mfi_oversold", "mfi_bull_div", "supertrend_bull",
            "force_index_div", "force_index_rising", "ha_bull", "donchian_up",
            "three_white_soldiers", "morning_star", "bullish_engulfing", "hammer",
            "psar_bull", "price_accel_pos", "unusual_calls", "options_bull",
            "lr_below_channel",
            # High-conviction patterns added for deeper synergy learning
            "pocket_pivot", "htf", "ema21_pullback", "ema21_touch",
            "mtf_triple", "mtf_conflict",
            "rs_line_new_high", "rs_line_trending",
            "vol_dry_up", "near_support", "near_key_support",
            "squeeze_potential", "unusual_calls", "options_bear",
            "high_short", "mfi_overbought",
        ]))
        e["entry_signals"] = list(dict.fromkeys(k for k in _SIGNAL_KEYS if signals.get(k)))
        e["signal_count_at_entry"] = len(e["entry_signals"])
        # SPY day return at entry: up/flat/down market context for trade outcome learning
        try:
            _spy_d1 = _fetch_spy_perf().get("d1", 0.0) or 0.0
            e["spy_day_return"] = round(float(_spy_d1), 2)
            e["spy_day_bucket"] = ("up" if _spy_d1 > 0.5 else "down" if _spy_d1 < -0.5 else "flat")
        except Exception:
            e["spy_day_return"] = 0.0
            e["spy_day_bucket"] = "flat"
        # Re-entry detection: was this ticker sold within the last 48h?
        try:
            _re_cutoff = datetime.now(timezone.utc) - timedelta(hours=48)
            _prior_sell = next((t for t in reversed(tlog.get("trades", []))
                               if t.get("ticker") == sym
                               and t.get("action") in ("SELL", "SELL_HALF", "COVER")
                               and t.get("pnl_pct") is not None
                               and datetime.fromisoformat(t["time"].replace("Z", "+00:00")) > _re_cutoff), None)
            if _prior_sell:
                e["is_reentry"] = True
                e["reentry_prior_pnl"] = _prior_sell.get("pnl_pct", 0.0)
                e["reentry_type"] = "winner" if _prior_sell.get("pnl_pct", 0) > 0 else "loser"
            else:
                e["is_reentry"] = False
        except Exception:
            e["is_reentry"] = False

        # ── N871-N880: entry state tags for advanced neurons ─────────────────
        try:
            _n871_rvol = float(signals.get("rvol", 1.0) or 1.0)
            _n871_chg  = float(signals.get("change_pct", 0) or 0)
            e["order_flow_imbalance_state"] = ("buy_dominated" if _n871_rvol >= 1.5 and _n871_chg > 0
                                               else "sell_dominated" if _n871_rvol >= 1.5 and _n871_chg < 0
                                               else "balanced_flow")
            _n872_roc5 = float(signals.get("roc5", 0) or 0)
            _n872_mslp = float(signals.get("macd_slope", 0) or 0)
            e["time_weighted_momentum_state"] = ("accelerating" if _n872_roc5 > 1 and _n872_mslp > 0
                                                 else "decelerating" if _n872_roc5 < -1 or _n872_mslp < 0
                                                 else "flat")
            e["relative_volume_burst_state"] = ("burst_3x" if _n871_rvol >= 3.0
                                                else "elevated_2x" if _n871_rvol >= 2.0
                                                else "normal_vol")
            _n874_cat = bool(signals.get("catalyst", False) or signals.get("news_catalyst", False)
                             or signals.get("earnings_beat", False) or int(signals.get("news_count_24h", 0) or 0) >= 5)
            e["catalyst_timing_state"] = "fresh_catalyst" if _n874_cat else "stale_catalyst"
            e["multi_timeframe_alignment_state"] = ("aligned_all" if signals.get("mtf_aligned")
                                                     else "mixed_signals")
            e["market_maker_activity_state"] = ("mm_active" if signals.get("rvol_surge") else "mm_normal")
            _n877_et_h = e.get("et_hour_at_entry", -1)
            e["alpha_decay_risk_state"] = ("low_decay" if 9 <= _n877_et_h <= 11
                                           else "high_decay" if _n877_et_h >= 15
                                           else "moderate_decay")
            _n878_52wh = float(signals.get("near_52w_high", 1.0) or 1.0)
            e["price_discovery_phase_state"] = ("discovery_up" if _n878_52wh >= 0.98
                                                else "established" if _n878_52wh >= 0.85
                                                else "recovery")
            _n879_obv = bool(signals.get("obv_rising", False))
            _n879_chg = float(signals.get("change_pct", 0) or 0)
            e["smart_money_divergence_state"] = ("diverging_bullish" if _n879_obv and _n879_chg < 0
                                                 else "diverging_bearish" if not _n879_obv and _n879_chg > 0
                                                 else "aligned")
            e["volatility_regime_shift_state"] = ("vol_expanding" if signals.get("hv_expanding")
                                                  else "vol_contracting" if signals.get("hv_contracting")
                                                  else "stable_vol")
        except Exception:
            pass

        # ── N891-N900: entry state tags ───────────────────────────────────────
        # VIX direction at entry (N892)
        try:
            _vix_dir_now = float(tlog.get("regime", {}).get("vix_1d", 0) or 0)
            e["vix_direction"] = ("rising" if _vix_dir_now > 1 else "falling" if _vix_dir_now < -1 else "flat")
        except Exception:
            e["vix_direction"] = "flat"
        # ET hour and minute at entry (N893)
        try:
            _now_utc_lt = datetime.now(timezone.utc)
            _yr_lt = _now_utc_lt.year
            _mar_lt = datetime(_yr_lt, 3, 8, 2, tzinfo=timezone.utc)
            _dst_s_lt = _mar_lt + timedelta(days=(6 - _mar_lt.weekday()) % 7)
            _nov_lt = datetime(_yr_lt, 11, 1, 2, tzinfo=timezone.utc)
            _dst_e_lt = _nov_lt + timedelta(days=(6 - _nov_lt.weekday()) % 7)
            _et_off_lt = -4 if _dst_s_lt <= _now_utc_lt < _dst_e_lt else -5
            _et_lt = _now_utc_lt + timedelta(hours=_et_off_lt)
            e["et_hour_at_entry"] = _et_lt.hour
            e["et_min_at_entry"]  = _et_lt.minute
        except Exception:
            e["et_hour_at_entry"] = -1
            e["et_min_at_entry"]  = 0
        # Win streak at entry (N894) — positive = wins, negative = losses
        try:
            _streak = 0
            for _pt in reversed(list(tlog.get("trades", []))):  # most recent first
                if _pt.get("action") not in ("SELL", "SELL_HALF", "COVER"): continue
                if _pt.get("pnl_pct") is None: continue
                _streak = 1 if _pt.get("pnl_pct", 0) > 0 else -1  # most recent result
                break
            e["win_streak_at_entry"] = _streak
        except Exception:
            e["win_streak_at_entry"] = 0
        # Capital utilization at entry (N896)
        try:
            _port_val = float(tlog.get("portfolio_value", 100000) or 100000)
            _bp_now = float(tlog.get("buying_power", _port_val) or _port_val)
            e["capital_util_pct"] = round((1 - _bp_now / max(_port_val, 1)) * 100, 1)
        except Exception:
            e["capital_util_pct"] = 50.0
        # SPY intraday direction at entry (N897)
        try:
            _spy_intra = float(tlog.get("spy_intraday_pct", 0) or 0)
            e["spy_intraday_dir"] = ("up" if _spy_intra > 0.2 else "down" if _spy_intra < -0.2 else "flat")
        except Exception:
            e["spy_intraday_dir"] = "flat"
        # Regime stability at entry (N898)
        try:
            _reg_hist = tlog.get("regime_history", [])
            _last_3_regimes = [r.get("r") for r in _reg_hist[-3:] if r.get("r")]
            _reg_stable = len(set(_last_3_regimes)) <= 1 and len(_last_3_regimes) >= 3
            e["regime_stability"] = ("established" if _reg_stable else "transitioning")
        except Exception:
            e["regime_stability"] = "established"
        # Score persistence (N899) — how many consecutive runs did this ticker appear?
        try:
            _persist_data = tlog.get("last_scan_persistence", {})
            e["persistence_runs"] = int(_persist_data.get(sym, 1))
        except Exception:
            e["persistence_runs"] = 1
        # Sectors advancing at entry (N900)
        try:
            _sec_trends = tlog.get("sector_etf_trends", {})
            e["sectors_advancing"] = sum(1 for sv in _sec_trends.values()
                                         if isinstance(sv, dict) and float(sv.get("chg1d", 0) or 0) > 0)
        except Exception:
            e["sectors_advancing"] = 5

    # ── Crypto-specific neuron state tags at BUY entry ────────────────────────
    # These fields are read back on SELL to update N881-N890 crypto neurons.
    if action == "BUY" and "/" in sym and signals:
        for _ckey in ("crypto_momentum_tier", "crypto_rsi_zone", "crypto_vol_surge",
                      "crypto_ema_cross", "crypto_dow", "crypto_asset_class",
                      "crypto_score_tier", "crypto_ai_score", "crypto_btc_dom",
                      "crypto_hour_utc"):
            if _ckey in signals:
                e[_ckey] = signals[_ckey]

    # ── Universal catch-all: preserve ALL neuron state fields from signals ───────
    # Neurons N100-N900+ store their entry state in _buy_signals_merged under keys
    # with suffixes like _state/_tier/_bucket/_perf as well as raw context fields
    # (adl_trend, cap_regime, entry_session, etc.). Without this block every key not
    # explicitly extracted above is silently dropped, so learning always falls back
    # to defaults. We copy ALL keys from signals that aren't already in e, excluding
    # large/noisy fields that would bloat the trade record.
    if action == "BUY" and signals:
        _SKIP_KEYS = frozenset({
            "raw_data", "bars", "history", "news_items", "order_book",
            "minute_bars", "daily_bars", "ticks", "depth",
        })
        for _sk, _sv in signals.items():
            if _sk not in e and _sk not in _SKIP_KEYS:
                # Only store scalars + short strings (skip large dicts/lists)
                if isinstance(_sv, (str, int, float, bool)) or _sv is None:
                    e[_sk] = _sv
                elif isinstance(_sv, list) and len(_sv) <= 10:
                    e[_sk] = _sv

    tlog.setdefault("trades", []).insert(0, e)
    tlog["trades"] = tlog["trades"][:1000]  # increased from 500 for 500 trades/day learning

    # Running stats
    stats = tlog.setdefault("stats", {"wins": 0, "losses": 0, "total_pnl": 0.0})
    if pnl is not None:
        stats["total_pnl"] = round(stats.get("total_pnl", 0) + pnl, 2)
        if pnl > 0:
            stats["wins"] = stats.get("wins", 0) + 1
        else:
            stats["losses"] = stats.get("losses", 0) + 1

    # Update signal performance stats when SELL closes a position
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        # Find matching BUY/SHORT for this ticker in recent trades
        for t in tlog.get("trades", []):
            if t.get("action") in ("BUY", "SHORT") and t.get("ticker") == sym and t.get("entry_signals"):
                perf = tlog.setdefault("signal_performance", {})
                _entry_sigs = t["entry_signals"]
                for sig in _entry_sigs:
                    sp = perf.setdefault(sig, {"wins": 0, "losses": 0, "total": 0,
                                               "total_pnl": 0.0, "best": 0.0, "worst": 0.0})
                    sp["total"] = sp.get("total", 0) + 1
                    sp["total_pnl"] = round(sp.get("total_pnl", 0.0) + pnl, 2)
                    if pnl > 0:
                        sp["wins"] = sp.get("wins", 0) + 1
                        sp["best"]  = max(sp.get("best", 0.0), pnl)
                    else:
                        sp["losses"] = sp.get("losses", 0) + 1
                        sp["worst"] = min(sp.get("worst", 0.0), pnl)
                    # Derived stats
                    t_cnt = sp["total"]
                    sp["win_rate"]  = round(sp["wins"] / t_cnt * 100, 1)  # stored as 0-100 for dashboard
                    sp["avg_pnl"]   = round(sp["total_pnl"] / t_cnt, 2)
                    sp["payoff_ratio"] = round(
                        sp.get("best", 0) / max(abs(sp.get("worst", -0.01)), 0.01), 2
                    ) if sp.get("worst", 0) < 0 else sp.get("best", 0)

                # ── Signal PAIR synergy tracking (neural synapse learning) ──
                # Tracks performance of signal COMBINATIONS, not just single signals.
                # When two signals fire together and a trade wins → that synapse strengthens.
                # When they fire together and lose → the synapse weakens.
                # Over time this finds the most powerful signal combinations in our system.
                if len(_entry_sigs) >= 2:
                    try:
                        _syn_perf = tlog.setdefault("signal_synergy", {})
                        _sorted_sigs = sorted(_entry_sigs[:8])  # expanded: top 8 signals for richer pairs
                        for _i in range(len(_sorted_sigs)):
                            for _j in range(_i + 1, len(_sorted_sigs)):
                                _pair_key = f"{_sorted_sigs[_i]}+{_sorted_sigs[_j]}"
                                _syn = _syn_perf.setdefault(_pair_key, {
                                    "wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0
                                })
                                _syn["total"] += 1
                                _syn["total_pnl"] = round(_syn["total_pnl"] + pnl, 2)
                                if pnl > 0: _syn["wins"] += 1
                                else:       _syn["losses"] += 1
                                _syn["win_rate"] = round(_syn["wins"] / _syn["total"] * 100, 1)
                                _syn["avg_pnl"]  = round(_syn["total_pnl"] / _syn["total"], 2)
                        # Keep top 80 pairs by win rate (weighted by frequency) — richer signal map
                        if len(_syn_perf) > 100:
                            _syn_sorted = sorted(_syn_perf.items(),
                                key=lambda x: -(x[1].get("win_rate",50) * min(1.0, x[1].get("total",0)/10.0)))
                            tlog["signal_synergy"] = dict(_syn_sorted[:80])
                        # ── 3-signal TRIPLE synergy (deepens pattern learning) ──────────
                        if len(_sorted_sigs) >= 3:
                            _tri_perf = tlog.setdefault("signal_triplets", {})
                            for _i2 in range(len(_sorted_sigs)):
                                for _j2 in range(_i2+1, len(_sorted_sigs)):
                                    for _k2 in range(_j2+1, len(_sorted_sigs)):
                                        _tri_key = f"{_sorted_sigs[_i2]}+{_sorted_sigs[_j2]}+{_sorted_sigs[_k2]}"
                                        _tri = _tri_perf.setdefault(_tri_key, {
                                            "wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0
                                        })
                                        _tri["total"] += 1
                                        _tri["total_pnl"] = round(_tri["total_pnl"] + pnl, 2)
                                        if pnl > 0: _tri["wins"] += 1
                                        else:       _tri["losses"] += 1
                                        _tri["win_rate"] = round(_tri["wins"] / _tri["total"] * 100, 1)
                                        _tri["avg_pnl"]  = round(_tri["total_pnl"] / _tri["total"], 2)
                            # Keep top 60 triplets by win rate weighted by frequency
                            if len(_tri_perf) > 80:
                                _tri_sorted = sorted(_tri_perf.items(),
                                    key=lambda x: -(x[1].get("win_rate",50) * min(1.0, x[1].get("total",0)/8.0)))
                                tlog["signal_triplets"] = dict(_tri_sorted[:60])
                    except Exception:
                        pass
                break

        # Rebuild signal_win_rates summary for the score() adaptive loop
        perf_all = tlog.get("signal_performance", {})
        tlog["signal_win_rates"] = {
            sig: {
                "win_rate": v.get("win_rate", 50.0),  # 0-100 scale for dashboard
                "total":    v.get("total", 0),
                "avg_pnl":  v.get("avg_pnl", 0),
            }
            for sig, v in perf_all.items()
            if v.get("total", 0) >= 3  # only trust with ≥3 samples
        }

    # Per-sector performance tracking (updated on every close)
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        _sector_key = SECTOR_MAP.get(sym, "other")
        _sec_perf = tlog.setdefault("sector_performance", {})
        _sp = _sec_perf.setdefault(_sector_key, {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
        _sp["total"] = _sp.get("total", 0) + 1
        _sp["total_pnl"] = round(_sp.get("total_pnl", 0.0) + pnl, 2)
        if pnl > 0:
            _sp["wins"] = _sp.get("wins", 0) + 1
        else:
            _sp["losses"] = _sp.get("losses", 0) + 1
        if _sp["total"] > 0:
            _sp["win_rate"] = round(_sp["wins"] / _sp["total"] * 100, 1)
            _sp["avg_pnl"]  = round(_sp["total_pnl"] / _sp["total"], 2)

    # Catalyst-type performance tracking
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        # Find matching BUY entry with catalyst info
        for t in tlog.get("trades", []):
            if t.get("action") == "BUY" and t.get("ticker") == sym and t.get("catalyst_type"):
                _cat_key = t["catalyst_type"]
                _cat_perf = tlog.setdefault("catalyst_performance", {})
                _cp = _cat_perf.setdefault(_cat_key, {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
                _cp["total"] = _cp.get("total", 0) + 1
                _cp["total_pnl"] = round(_cp.get("total_pnl", 0.0) + pnl, 2)
                if pnl > 0:
                    _cp["wins"] = _cp.get("wins", 0) + 1
                else:
                    _cp["losses"] = _cp.get("losses", 0) + 1
                if _cp["total"] > 0:
                    _cp["win_rate"] = round(_cp["wins"] / _cp["total"] * 100, 1)
                    _cp["avg_pnl"]  = round(_cp["total_pnl"] / _cp["total"], 2)
                break

    # Regime-based performance tracking (bull/bear/choppy performance breakdown)
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        try:
            # Look up the regime at time of entry from the trade record
            _buy_entry = _cached_buy_rec
            _reg_key = "unknown"
            if _buy_entry:
                _reg_key = _buy_entry.get("regime", "unknown")
            else:
                # Use current regime as fallback
                _cur_reg = tlog.get("regime", {})
                _reg_key = _cur_reg if isinstance(_cur_reg, str) else (_cur_reg.get("regime", "unknown") if isinstance(_cur_reg, dict) else "unknown")
            _reg_perf = tlog.setdefault("regime_performance", {})
            _rp = _reg_perf.setdefault(str(_reg_key), {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
            _rp["total"] = _rp.get("total", 0) + 1
            _rp["total_pnl"] = round(_rp.get("total_pnl", 0.0) + pnl, 2)
            if pnl > 0:
                _rp["wins"] = _rp.get("wins", 0) + 1
            else:
                _rp["losses"] = _rp.get("losses", 0) + 1
            if _rp["total"] > 0:
                _rp["win_rate"] = round(_rp["wins"] / _rp["total"] * 100, 1)
                _rp["avg_pnl"]  = round(_rp["total_pnl"] / _rp["total"], 2)
        except Exception:
            pass

    # Hold time performance tracking
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        try:
            _buy_t = _cached_buy_rec
            if _buy_t and _buy_t.get("time"):
                from datetime import datetime as _hdt, timezone as _htz
                _entry_t = _hdt.fromisoformat(_buy_t["time"].replace("Z", "+00:00"))
                _hold_min = max(0, (_entry_t.utcnow().replace(tzinfo=_htz.utc) - _entry_t).total_seconds() / 60)
                _hold_d  = int(_hold_min / 1440)  # convert to days
                _ht_bucket = "0-2d" if _hold_d <= 2 else ("3-7d" if _hold_d <= 7 else ("8-14d" if _hold_d <= 14 else "15d+"))
                _ht_perf = tlog.setdefault("hold_time_performance", {})
                _htp = _ht_perf.setdefault(_ht_bucket, {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
                _htp["total"] = _htp.get("total", 0) + 1
                _htp["total_pnl"] = round(_htp.get("total_pnl", 0.0) + pnl, 2)
                if pnl > 0:
                    _htp["wins"] = _htp.get("wins", 0) + 1
                else:
                    _htp["losses"] = _htp.get("losses", 0) + 1
                if _htp["total"] > 0:
                    _htp["win_rate"] = round(_htp["wins"] / _htp["total"] * 100, 1)
                    _htp["avg_pnl"]  = round(_htp["total_pnl"] / _htp["total"], 2)
                # Intraday hold time buckets (more granular for scalp-focused system)
                if _hold_d == 0:
                    _intra_bucket = ("<30min" if _hold_min < 30 else
                                     "30-60min" if _hold_min < 60 else
                                     "60-90min" if _hold_min < 90 else
                                     "90-120min" if _hold_min < 120 else "120min+")
                    _intra_perf = tlog.setdefault("intraday_hold_time_perf", {})
                    _ihtp = _intra_perf.setdefault(_intra_bucket, {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
                    _ihtp["total"] = _ihtp.get("total", 0) + 1
                    _ihtp["total_pnl"] = round(_ihtp.get("total_pnl", 0.0) + pnl, 2)
                    if pnl > 0: _ihtp["wins"] = _ihtp.get("wins", 0) + 1
                    else: _ihtp["losses"] = _ihtp.get("losses", 0) + 1
                    if _ihtp["total"] > 0:
                        _ihtp["win_rate"] = round(_ihtp["wins"] / _ihtp["total"] * 100, 1)
                        _ihtp["avg_pnl"]  = round(_ihtp["total_pnl"] / _ihtp["total"], 2)
        except Exception:
            pass

    # ── Ticker Memory Neuron: per-ticker win/loss history ────────────────────
    # The bot remembers which tickers it's historically good or bad at.
    # A ticker with 70%+ WR gets a score boost next time; <35% WR gets a penalty.
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        try:
            _tk_mem = tlog.setdefault("ticker_memory", {})
            _tm = _tk_mem.setdefault(sym, {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
            _tm["total"] = _tm.get("total", 0) + 1
            _tm["total_pnl"] = round(_tm.get("total_pnl", 0.0) + pnl, 2)
            if pnl > 0: _tm["wins"] = _tm.get("wins", 0) + 1
            else: _tm["losses"] = _tm.get("losses", 0) + 1
            if _tm["total"] > 0:
                _tm["win_rate"] = round(_tm["wins"] / _tm["total"] * 100, 1)
                _tm["avg_pnl"]  = round(_tm["total_pnl"] / _tm["total"], 2)
            # Trim to top 100 tickers by trade count
            if len(_tk_mem) > 120:
                tlog["ticker_memory"] = dict(sorted(_tk_mem.items(), key=lambda x: -x[1].get("total", 0))[:100])
        except Exception:
            pass

    # ── VIX Bracket Neuron: performance by volatility regime ────────────────
    # Tracks win rate in low/normal/elevated/high VIX environments.
    # The bot learns whether it should be more/less aggressive at each VIX level.
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        try:
            _buy_t2 = _cached_buy_rec
            _vix_ent = _buy_t2.get("vix_at_entry") if _buy_t2 else None
            if _vix_ent is not None:
                _vbkt = ("low" if float(_vix_ent) < 14 else
                         "normal" if float(_vix_ent) < 20 else
                         "elevated" if float(_vix_ent) < 28 else "high")
                _vix_perf = tlog.setdefault("vix_bracket_performance", {})
                _vp = _vix_perf.setdefault(_vbkt, {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
                _vp["total"] = _vp.get("total", 0) + 1
                _vp["total_pnl"] = round(_vp.get("total_pnl", 0.0) + pnl, 2)
                if pnl > 0: _vp["wins"] = _vp.get("wins", 0) + 1
                else: _vp["losses"] = _vp.get("losses", 0) + 1
                if _vp["total"] > 0:
                    _vp["win_rate"] = round(_vp["wins"] / _vp["total"] * 100, 1)
                    _vp["avg_pnl"]  = round(_vp["total_pnl"] / _vp["total"], 2)
        except Exception:
            pass

    # ── 30-Minute Window Neuron: fine-grained time-of-day scoring ───────────
    # More precise than hour-level: learns "9:30 AM ET is great, 9:00 AM is rough"
    # Key "HHMM" is the UTC 30-min window when the BUY was entered.
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        try:
            _buy_t3 = _cached_buy_rec
            if _buy_t3 and _buy_t3.get("time"):
                _entry_dt3 = datetime.fromisoformat(_buy_t3["time"].replace("Z", "+00:00"))
                _hw_key = f"{_entry_dt3.hour:02d}{'30' if _entry_dt3.minute >= 30 else '00'}"
                _hw_perf = tlog.setdefault("halfhour_performance", {})
                _hwp = _hw_perf.setdefault(_hw_key, {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
                _hwp["total"] = _hwp.get("total", 0) + 1
                _hwp["total_pnl"] = round(_hwp.get("total_pnl", 0.0) + pnl, 2)
                if pnl > 0: _hwp["wins"] = _hwp.get("wins", 0) + 1
                else: _hwp["losses"] = _hwp.get("losses", 0) + 1
                if _hwp["total"] > 0:
                    _hwp["win_rate"] = round(_hwp["wins"] / _hwp["total"] * 100, 1)
                    _hwp["avg_pnl"]  = round(_hwp["total_pnl"] / _hwp["total"], 2)
        except Exception:
            pass

    # ── Earnings Proximity Neuron: learn near-earnings trade outcomes ─────────
    # Tracks win rate by how close to earnings the bot entered.
    # Learns: are pre-earnings drift plays working? Are day-of entries too risky?
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        try:
            _buy_t4 = _cached_buy_rec
            _earn_days = _buy_t4.get("earnings_days_at_entry") if _buy_t4 else None
            if _earn_days is not None:
                _earn_bkt = ("0-2d" if _earn_days <= 2 else
                             "3-7d"  if _earn_days <= 7  else
                             "8-20d" if _earn_days <= 20 else "21d+")
                _earn_perf = tlog.setdefault("earnings_days_bucket_perf", {})
                _ep = _earn_perf.setdefault(_earn_bkt, {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
                _ep["total"] = _ep.get("total", 0) + 1
                _ep["total_pnl"] = round(_ep.get("total_pnl", 0.0) + pnl, 2)
                if pnl > 0: _ep["wins"] = _ep.get("wins", 0) + 1
                else: _ep["losses"] = _ep.get("losses", 0) + 1
                if _ep["total"] > 0:
                    _ep["win_rate"] = round(_ep["wins"] / _ep["total"] * 100, 1)
                    _ep["avg_pnl"]  = round(_ep["total_pnl"] / _ep["total"], 2)
        except Exception:
            pass

    # ── RVOL Performance Neuron: learn optimal entry volume threshold ─────────
    # High relative volume at entry often confirms institutional participation.
    # The bot learns: does RVOL > 3x actually lead to better outcomes?
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        try:
            _buy_t5 = _cached_buy_rec
            _rvol_e = float(_buy_t5.get("rvol_at_entry", 1.0) or 1.0) if _buy_t5 else None
            if _rvol_e is not None:
                _rv_bkt = ("low" if _rvol_e < 1.5 else
                           "normal" if _rvol_e < 2.5 else
                           "high"   if _rvol_e < 4.0 else "surge")
                _rvol_perf = tlog.setdefault("rvol_perf", {})
                _rvp = _rvol_perf.setdefault(_rv_bkt, {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
                _rvp["total"] = _rvp.get("total", 0) + 1
                _rvp["total_pnl"] = round(_rvp.get("total_pnl", 0.0) + pnl, 2)
                if pnl > 0: _rvp["wins"] = _rvp.get("wins", 0) + 1
                else: _rvp["losses"] = _rvp.get("losses", 0) + 1
                if _rvp["total"] > 0:
                    _rvp["win_rate"] = round(_rvp["wins"] / _rvp["total"] * 100, 1)
                    _rvp["avg_pnl"]  = round(_rvp["total_pnl"] / _rvp["total"], 2)
        except Exception:
            pass

    # ── Market Quality Threshold Neuron: learn minimum conditions ─────────────
    # Tracks performance by market quality at time of entry (0-100 composite).
    # Learns: below what quality score do entries fail? Above what do they thrive?
    if action in ("SELL", "SELL_HALF", "COVER") and pnl is not None:
        try:
            _buy_t6 = _cached_buy_rec
            _mq_e = int(_buy_t6.get("mkt_quality_at_entry", 50) or 50) if _buy_t6 else None
            if _mq_e is not None:
                _mq_bkt = ("poor" if _mq_e < 40 else
                           "fair"      if _mq_e < 60 else
                           "good"      if _mq_e < 75 else "excellent")
                _mq_perf = tlog.setdefault("mkt_quality_perf", {})
                _mqp = _mq_perf.setdefault(_mq_bkt, {"wins": 0, "losses": 0, "total": 0, "total_pnl": 0.0})
                _mqp["total"] = _mqp.get("total", 0) + 1
                _mqp["total_pnl"] = round(_mqp.get("total_pnl", 0.0) + pnl, 2)
                if pnl > 0: _mqp["wins"] = _mqp.get("wins", 0) + 1
                else: _mqp["losses"] = _mqp.get("losses", 0) + 1
                if _mqp["total"] > 0:
                    _mqp["win_rate"] = round(_mqp["wins"] / _mqp["total"] * 100, 1)
                    _mqp["avg_pnl"]  = round(_mqp["total_pnl"] / _mqp["total"], 2)
        except Exception:
            pass

