            _wrp["total_pnl"] = round(_wrp.get("total_pnl", 0.0) + pnl, 2)
            if pnl > 0: _wrp["wins"] = _wrp.get("wins", 0) + 1
            else:        _wrp["losses"] = _wrp.get("losses", 0) + 1
