            _nsl_adj += _nde("float_rotation_v1_perf", _n542_rot_q)

            # N552: ORB quality (orb_breakout/inside_orb/orb_breakdown)
            _n552_orb_v  = bool(d.get("orb_breakout", d.get("orb_up", False)))
