            _nsl_adj += _nde("insider_activity_v1_perf", _n644_ins_q)

            # N433: Price momentum 5D (strong_up/mild_up/flat_neg)
            _n433_chg5_v = float(d.get("rs5", d.get("change_5d", 0)) or 0)
