            _nsl_adj += _nde("catalyst_fresh_v1_perf", _n456_fresh_q)

            # N550: Consecutive up days (streak_entry/neutral_entry/pullback_entry)
            _n550_consec_v = int(d.get("consec_up", d.get("consec_green", 0)) or 0)
