            _sec_win_rate = tlog.get("sector_performance", {}).get(sec, {}).get("win_rate", 50) or 50
            _sec_trade_n  = tlog.get("sector_performance", {}).get(sec, {}).get("total", 0) or 0
            if _sec_trade_n >= 4:
                _sec_wr_adj = round((_sec_win_rate - 50) / 10)  # -5..+5 overlay on sector adj
